-- ============================================================================
-- Quiz Seed: Acts — Part 4 (Chapters 19–24)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══════════════ CHAPTERS 19–21 ═══════════════

-- ═══ Acts Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 19, 'kids', 1, 'What happened when Paul laid his hands on twelve men in Ephesus?', 'The Holy Ghost came on them and they spoke with tongues and prophesied', 'They immediately became rich', 'They could suddenly speak many languages', 'They fell asleep for three days', 'a', 'Acts 19:6 — "And when Paul had laid his hands upon them, the Holy Ghost came on them; and they spake with tongues, and prophesied."'),
('Acts', 19, 'kids', 2, 'What did many people in Ephesus do with their magic books after believing in Jesus?', 'They brought them together and burned them in front of everyone', 'They gave them to the apostles', 'They sold them at the market', 'They hid them in a cave', 'a', 'Acts 19:19 — "Many of them also which used curious arts brought their books together, and burned them before all men."'),
('Acts', 19, 'kids', 3, 'Why was there a big riot in Ephesus?', 'A silversmith named Demetrius was angry because Paul''s preaching was hurting his business of making silver shrines of the goddess Diana', 'Paul accidentally broke a statue', 'There was a fire in the marketplace', 'An earthquake destroyed the temple', 'a', 'Acts 19:24-27 — "A certain man named Demetrius, a silversmith, which made silver shrines for Diana, brought no small gain unto the craftsmen... this Paul hath persuaded and turned away much people, saying that they be no gods, which are made with hands."'),
-- Teens
('Acts', 19, 'teens', 1, 'What did Paul discover about the twelve disciples in Ephesus?', 'They had only received John''s baptism and had not even heard whether there be any Holy Ghost — Paul baptised them in the name of the Lord Jesus', 'They were already fully taught in the faith', 'They were Gentiles who knew nothing about God', 'They were Pharisees pretending to be Christians', 'a', 'Acts 19:2-5 — "He said unto them, Have ye received the Holy Ghost since ye believed? And they said unto him, We have not so much as heard whether there be any Holy Ghost... When they heard this, they were baptized in the name of the Lord Jesus."'),
('Acts', 19, 'teens', 2, 'What happened when the seven sons of Sceva tried to cast out a demon using Jesus'' name?', 'The evil spirit said "Jesus I know, and Paul I know; but who are ye?" and the possessed man leaped on them, overpowered them, and they fled naked and wounded', 'The demon left immediately', 'Nothing happened at all', 'They successfully cast out the demon', 'a', 'Acts 19:15-16 — "And the evil spirit answered and said, Jesus I know, and Paul I know; but who are ye? And the man in whom the evil spirit was leaped on them, and overcame them, and prevailed against them, so that they fled out of that house naked and wounded."'),
('Acts', 19, 'teens', 3, 'How much were the magic books worth that the Ephesian believers burned?', 'Fifty thousand pieces of silver', 'One thousand pieces of silver', 'Five hundred pieces of silver', 'One hundred pieces of gold', 'a', 'Acts 19:19 — "And they counted the price of them, and found it fifty thousand pieces of silver."'),
('Acts', 19, 'teens', 4, 'What was Demetrius''s real complaint against Paul?', 'That Paul was destroying their profitable trade in silver shrines of Diana by convincing people that gods made with hands are not real gods', 'That Paul owed him money', 'That Paul was teaching people to worship the emperor', 'That Paul had stolen silver from his shop', 'a', 'Acts 19:26-27 — "This Paul hath persuaded and turned away much people, saying that they be no gods, which are made with hands: So that not only this our craft is in danger to be set at nought; but also that the temple of the great goddess Diana should be despised."'),
('Acts', 19, 'teens', 5, 'How was the riot in Ephesus finally calmed down?', 'The town clerk told the crowd they could take the matter to the proper courts and dismissed the assembly, warning that they were in danger of being charged with rioting by Rome', 'Paul preached a sermon that calmed everyone', 'Roman soldiers arrived and arrested the crowd', 'A thunderstorm scattered the people', 'a', 'Acts 19:35,40-41 — "The townclerk... appeased the people... we are in danger to be called in question for this day''s uproar... And when he had thus spoken, he dismissed the assembly."'),
-- Adults
('Acts', 19, 'adults', 1, 'What does the Ephesian disciples'' ignorance of the Holy Spirit (19:1-7) reveal about incomplete Christianity?', 'These disciples represent a transitional group — they had John''s preparatory baptism but not the full Christian experience. Their ignorance of the Spirit shows that partial gospel knowledge exists: they believed in the coming Messiah but had not received the Spirit that marks new-covenant life. Paul''s re-baptism "in the name of the Lord Jesus" and the Spirit''s descent completed their initiation', 'They were not genuine seekers', 'John''s baptism was identical to Christian baptism', 'The Holy Spirit was not available until later', 'a', 'Acts 19:1-7 — These disciples knew John''s baptism of repentance but not Jesus'' baptism of the Spirit. Paul completes their initiation: re-baptism in Jesus'' name (v.5) and Spirit reception through laying on of hands (v.6). This Ephesian "mini-Pentecost" parallels the Jewish (ch.2), Samaritan (ch.8), and Gentile (ch.10) Spirit-receptions.'),
('Acts', 19, 'adults', 2, 'What does the sons of Sceva episode teach about the difference between invoking Jesus'' name and having a relationship with Him?', 'The sons of Sceva used Jesus'' name as a magical formula ("We adjure you by Jesus whom Paul preacheth") without personal faith. The demon''s response — "Jesus I know, and Paul I know; but who are ye?" — distinguishes between genuine authority (which comes through relationship with Christ) and counterfeit authority (which appropriates the name without the person). Spiritual power is relational, not formulaic', 'Using Jesus'' name always works regardless of faith', 'Demons do not recognise any human authority', 'The incident was purely symbolic', 'a', 'Acts 19:13-16 — The demon knows Jesus (ginoskein = intimate knowledge) and Paul (epistamai = awareness), but the exorcists are unknown. Their formula — "by Jesus whom Paul preacheth" — is secondhand faith. The beating they receive demonstrates that spiritual authority cannot be borrowed, traded, or faked.'),
('Acts', 19, 'adults', 3, 'What is the significance of the public burning of magic books worth fifty thousand pieces of silver?', 'The burning demonstrates radical repentance — the Ephesian converts destroyed their expensive occult materials publicly, making reconciliation with sorcery impossible. Fifty thousand drachmas (equivalent to 137 years of average wages) shows the economic cost of discipleship. Luke connects this to "so mightily grew the word of God and prevailed" (v.20) — the word conquers when believers break with their past', 'The burning was a minor event', 'They burned the books because they were old', 'Only a few books were destroyed', 'a', 'Acts 19:19-20 — "Fifty thousand pieces of silver" is an enormous sum — demonstrating the depth of Ephesus''s occult culture and the radicality of conversion. Public burning ensured no relapse. Luke''s progress report (v.20) directly follows: the word''s power is demonstrated by believers'' willingness to sacrifice everything.'),
('Acts', 19, 'adults', 4, 'How does the Demetrius riot illustrate the economic dimension of the gospel''s impact?', 'Paul''s preaching that "gods made with hands are not real gods" threatened the entire idol-manufacturing economy — Demetrius frames his complaint as both economic ("our craft is in danger") and religious ("the temple of Diana despised"). The gospel inevitably disrupts economic systems built on false worship. Luke shows that the gospel has real-world economic consequences, and those who profit from idolatry resist it violently', 'The riot was purely religious', 'Paul was deliberately targeting businesses', 'Economics played no role in the opposition', 'a', 'Acts 19:25-27 — Demetrius''s argument moves from economics (v.25, "our wealth") to religion (v.27, "Diana despised"). The intertwining of profit and piety is the real issue. When the gospel challenges idolatry, it necessarily challenges economies built on idolatry. The same pattern appears with the Philippian slave girl (16:19).'),
('Acts', 19, 'adults', 5, 'What does Paul''s two-year teaching ministry in the school of Tyrannus (19:9-10) reveal about his long-term strategy?', 'Paul shifted from itinerant synagogue preaching to sustained daily teaching in a rented lecture hall for two years, resulting in "all they which dwelt in Asia heard the word of the Lord." Ephesus became a regional hub from which the gospel spread throughout the entire Roman province of Asia. Paul used a strategic urban centre to evangelise an entire region through trained disciples who fanned out', 'Paul stayed because he could not find another city', 'Two years was an unusually short stay', 'The school was his permanent home', 'a', 'Acts 19:9-10 — "Disputing daily in the school of one Tyrannus. And this continued by the space of two years; so that all they which dwelt in Asia heard the word of the Lord Jesus." Paul''s Ephesus strategy: teach intensively in a central hub, and trained converts carry the gospel to surrounding cities (likely how Colossae, Laodicea, and Hierapolis were reached — Colossians 1:7, 4:13).'),
('Acts', 19, 'adults', 6, 'What does the town clerk''s speech (19:35-41) reveal about Roman civic administration and Christian apologetics?', 'The clerk''s speech is a secular defence of the Christians: he affirms that Paul and his companions are "neither robbers of churches, nor yet blasphemers of your goddess" (v.37). He channels the dispute into proper legal channels and warns of Roman intervention. Luke uses this Roman official''s testimony to show that Christianity was not a public threat — part of Acts'' ongoing legal apologetic', 'The clerk was a secret Christian', 'His speech was irrelevant to the narrative', 'He was hostile to Paul', 'a', 'Acts 19:37,40 — The clerk''s testimony that Christians are not temple-robbers or blasphemers provides legal vindication. His warning about Rome ("we are in danger to be called in question for this day''s uproar") aligns the church with civic order and paints the rioters as the real troublemakers. Luke consistently uses Roman officials to vindicate Christians.'),
('Acts', 19, 'adults', 7, 'How does Acts 19:20 ("So mightily grew the word of God and prevailed") function as a narrative summary?', 'This is Luke''s fifth progress report (cf. 6:7, 9:31, 12:24, 16:5). Each marks the gospel''s advance past a major obstacle. Here, the word prevails over occultism (the magic books), counterfeit spirituality (sons of Sceva), and economic opposition (Demetrius). The verb "prevailed" (ischuen) means to demonstrate strength — the word is a conquering force that overcomes all opposition', 'It is a minor transitional phrase', 'The word''s growth stopped after this', 'Only Luke uses such summaries', 'a', 'Acts 19:20 — "So mightily grew the word of God and prevailed." The Greek katischuen means "won strength against" — military language for victory. After each obstacle (occult practices, fake exorcists, economic riot), the word grows stronger. Luke''s progress reports are theological declarations: God''s word cannot be stopped.'),
('Acts', 19, 'adults', 8, 'What does the Ephesian ministry reveal about the comprehensive nature of the gospel''s confrontation with culture?', 'In Ephesus, the gospel confronts intellectual paganism (the synagogue and school of Tyrannus), popular superstition (magic books and exorcism), economic vested interests (silversmith guild), and civic religion (the Diana cult). The gospel does not leave any sphere of life unchallenged — it is not a private religious opinion but a total worldview that transforms minds, practices, economics, and public life', 'The gospel only affected religious practices', 'Ephesus was culturally unaffected by Paul', 'The gospel addressed only individual salvation', 'a', 'Acts 19 presents a comprehensive gospel impact: intellectual conversion (vv.8-10), supernatural confrontation (vv.11-16), moral transformation (vv.18-19), economic disruption (vv.24-27), and civic upheaval (vv.28-41). Ephesus is Luke''s showcase of what happens when the gospel fully engages a major city.');

-- ═══ Acts Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 20, 'kids', 1, 'What happened to the young man named Eutychus who fell asleep during Paul''s long sermon?', 'He fell from the third floor window and died, but Paul went down and embraced him and said his life was in him', 'He woke up and apologised', 'He was carried home to sleep', 'Paul shortened his sermon', 'a', 'Acts 20:9-10 — "And there sat in a window a certain young man named Eutychus, being fallen into a deep sleep: and as Paul was long preaching, he sunk down with sleep, and fell down from the third loft, and was taken up dead. And Paul went down, and fell on him, and embracing him said, Trouble not yourselves; for his life is in him."'),
('Acts', 20, 'kids', 2, 'Why were the Ephesian elders sad when Paul said goodbye to them?', 'Because Paul said they would never see his face again', 'Because Paul gave them too much work to do', 'Because it was raining that day', 'Because they had to walk a long distance', 'a', 'Acts 20:38 — "Sorrowing most of all for the words which he spake, that they should see his face no more."'),
('Acts', 20, 'kids', 3, 'What did Paul say he had not coveted from anyone?', 'Silver, gold, or clothing — his own hands had provided for his needs and the needs of those with him', 'Food and water', 'Houses and land', 'Horses and chariots', 'a', 'Acts 20:33-34 — "I have coveted no man''s silver, or gold, or apparel. Yea, ye yourselves know, that these hands have ministered unto my necessities, and to them that were with me."'),
-- Teens
('Acts', 20, 'teens', 1, 'What did Paul tell the Ephesian elders to watch out for?', 'Grievous wolves who would come in among them, not sparing the flock — and even from among themselves men would arise, speaking perverse things to draw away disciples', 'Roman soldiers who would destroy their church', 'False prophets who would predict earthquakes', 'Tax collectors who would steal their money', 'a', 'Acts 20:29-30 — "For I know this, that after my departing shall grievous wolves enter in among you, not sparing the flock. Also of your own selves shall men arise, speaking perverse things, to draw away disciples after them."'),
('Acts', 20, 'teens', 2, 'What did Paul say he was going to Jerusalem to face?', 'Bonds and afflictions await me — but none of these things move me, neither count I my life dear unto myself, so that I might finish my course with joy', 'A celebration in his honour', 'A new position as high priest', 'Freedom from all persecution', 'a', 'Acts 20:23-24 — "The Holy Ghost witnesseth in every city, saying that bonds and afflictions abide me. But none of these things move me, neither count I my life dear unto myself, so that I might finish my course with joy, and the ministry, which I have received of the Lord Jesus."'),
('Acts', 20, 'teens', 3, 'What responsibility did Paul give to the Ephesian elders?', 'Take heed unto yourselves and to all the flock, over the which the Holy Ghost hath made you overseers, to feed the church of God', 'Build a new temple in Ephesus', 'Collect money for Rome', 'Write new books of the Bible', 'a', 'Acts 20:28 — "Take heed therefore unto yourselves, and to all the flock, over the which the Holy Ghost hath made you overseers, to feed the church of God, which he hath purchased with his own blood."'),
('Acts', 20, 'teens', 4, 'What words of Jesus did Paul quote that are not recorded in the Gospels?', 'It is more blessed to give than to receive', 'Do unto others as you would have them do unto you', 'Love your neighbour as yourself', 'Judge not, that ye be not judged', 'a', 'Acts 20:35 — "I have shewed you all things, how that so labouring ye ought to support the weak, and to remember the words of the Lord Jesus, how he said, It is more blessed to give than to receive."'),
('Acts', 20, 'teens', 5, 'How did Paul describe his ministry among the Ephesians?', 'He had served the Lord with all humility, with many tears and temptations, kept back nothing profitable, and taught publicly and from house to house', 'He had worked alone without any help', 'He only preached on special occasions', 'He avoided all difficulties and conflicts', 'a', 'Acts 20:19-20 — "Serving the Lord with all humility of mind, and with many tears, and temptations... And how I kept back nothing that was profitable unto you, but have shewed you, and have taught you publickly, and from house to house."'),
-- Adults
('Acts', 20, 'adults', 1, 'How does Paul''s Miletus speech (20:17-38) function as his pastoral testament?', 'This is Paul''s only speech in Acts addressed to Christians (all others are to unbelievers or officials). It serves as a farewell address modelled on Moses'' farewell (Deuteronomy), Samuel''s farewell (1 Samuel 12), and Jesus'' farewell discourse (John 13-17). It covers his past ministry (vv.18-21), his future suffering (vv.22-24), warnings about false teachers (vv.28-31), and commendation to God''s grace (vv.32-35)', 'It was a casual goodbye with no structure', 'Paul addressed a crowd of unbelievers', 'The speech has no Old Testament precedent', 'a', 'Acts 20:17-38 — The farewell speech genre includes: review of past faithfulness (vv.18-21), prediction of future danger (vv.22-25,29-30), commission to the next generation (v.28), and commendation to God (v.32). Paul follows the pattern of Moses, Joshua, Samuel, and Jesus — a final charge from a departing leader.'),
('Acts', 20, 'adults', 2, 'What does "the church of God, which he hath purchased with his own blood" (20:28) reveal theologically?', 'This is one of the highest Christological statements in Acts: "God... purchased with his own blood" attributes the blood of the cross to God Himself. Whether read as "God''s own blood" or "the blood of his Own [Son]," it connects the atonement directly to the divine nature. The church''s value is measured by its purchase price — the blood of God incarnate', 'The phrase has no Christological significance', 'It refers to animal blood', 'Paul was speaking metaphorically about effort', 'a', 'Acts 20:28 — "The church of God, which he hath purchased with his own blood." The Greek (tou idiou haimatos) is striking: God''s own blood purchased the church. This implies the deity of Christ (whose blood was shed) and the infinite value of the atonement. The church is precious because its purchase price was infinite.'),
('Acts', 20, 'adults', 3, 'What does Paul''s warning about "grievous wolves" (20:29-30) reveal about threats to the church?', 'Paul identifies two threats: external ("grievous wolves" entering from outside) and internal ("of your own selves shall men arise, speaking perverse things"). The internal threat is more dangerous because it comes from trusted leaders. False teaching that draws disciples away from the truth is the church''s greatest danger — worse than persecution, which typically strengthens the church', 'Only external threats endanger the church', 'False teachers are easily identified', 'Paul was speaking about literal wolves', 'a', 'Acts 20:29-30 — Two sources of danger: wolves entering from outside and men arising from within. The internal threat ("of your own selves") echoes Jesus'' warning about false prophets in sheep''s clothing (Matthew 7:15). Church history confirms Paul''s prediction: the Ephesian church later battled internal heresy (Revelation 2:2, 1 Timothy 1:3).'),
('Acts', 20, 'adults', 4, 'How does Paul''s quotation of an unrecorded saying of Jesus ("It is more blessed to give than to receive," 20:35) affect our understanding of the Gospel traditions?', 'This saying, not found in any canonical Gospel, demonstrates that the written Gospels do not contain everything Jesus said (cf. John 21:25). The early church preserved oral traditions of Jesus'' sayings (agrapha) alongside the written accounts. Paul''s access to authentic Jesus traditions through the apostolic community shows the richness of early oral tradition', 'Paul invented this saying', 'Only written Gospel sayings are authentic', 'This contradicts the Gospels', 'a', 'Acts 20:35 — "The words of the Lord Jesus, how he said, It is more blessed to give than to receive." This agraphon (unwritten saying of Jesus) confirms John 21:25 ("many other things which Jesus did"). Paul received oral tradition (cf. 1 Corinthians 11:23, 15:3) alongside what was later written in the Gospels.'),
('Acts', 20, 'adults', 5, 'What ecclesiological terms does Paul use interchangeably in 20:17,28, and what does this imply?', 'Paul summons "elders" (presbuteroi, v.17), tells them the Holy Ghost made them "overseers" (episkopoi, v.28), and commands them to "feed" (poimainein = shepherd) the flock. The three terms — elder, overseer, shepherd — describe the same office from different angles: elder (maturity/dignity), overseer (function/responsibility), shepherd (care/protection). This interchangeability argues against rigid hierarchical distinctions', 'The three terms refer to three different offices', 'Only the term "elder" has any significance', 'Paul was confused about church structure', 'a', 'Acts 20:17,28 — Elders (presbuteroi) are called overseers (episkopoi) who shepherd (poimainein) the flock. The same leaders bear all three designations. This parallels 1 Peter 5:1-2 ("elders... feed/shepherd the flock... taking the oversight") and Titus 1:5,7 (where elder and overseer are used for the same person).'),
('Acts', 20, 'adults', 6, 'What does Paul mean by "I am pure from the blood of all men" (20:26)?', 'Paul echoes Ezekiel 33:1-9''s watchman metaphor — if the watchman warns and the people do not listen, their blood is on their own heads; but if he fails to warn, their blood is on him. Paul''s faithful proclamation of "all the counsel of God" (v.27) means he bears no responsibility for those who reject the gospel. He has discharged his duty as Christ''s watchman', 'Paul was saying he never hurt anyone physically', 'He was boasting about his moral perfection', 'The phrase is a Roman legal defence', 'a', 'Acts 20:26-27 — "I am pure from the blood of all men. For I have not shunned to declare unto you all the counsel of God." The Ezekiel 33 watchman principle: the herald who faithfully declares the message is freed from accountability for the hearers'' response. Paul''s conscience is clear because he withheld nothing.'),
('Acts', 20, 'adults', 7, 'How does the Eutychus incident (20:7-12) provide insights into early Christian worship?', 'The passage reveals several worship practices: meeting on "the first day of the week" (Sunday, v.7), "breaking of bread" (likely Lord''s Supper, v.7), and extended teaching ("Paul preached unto them... continued his speech until midnight," v.7). The setting — an upper room with many lamps (v.8), an extended gathering — shows early Christians worshipping in homes with both sacramental and teaching elements', 'Early Christians only met on Saturday', 'The incident tells us nothing about worship', 'Breaking of bread was an ordinary meal', 'a', 'Acts 20:7-8 — "Upon the first day of the week, when the disciples came together to break bread, Paul preached unto them... there were many lights in the upper chamber." Sunday gathering, Lord''s Supper, extended teaching, domestic setting, evening meeting — these details provide a window into first-century house-church worship.'),
('Acts', 20, 'adults', 8, 'What does Paul''s phrase "I count not my life dear unto myself" (20:24) reveal about apostolic motivation?', 'Paul subordinates self-preservation to mission completion — his life''s value is measured not by its length but by its faithfulness to the calling. "Finish my course with joy" echoes an athletic metaphor (cf. 2 Timothy 4:7). The apostle''s motivation is not survival but obedience. This transforms suffering from obstacle to opportunity and fear into freedom', 'Paul had a death wish', 'He was indifferent to his own wellbeing', 'This was rhetorical exaggeration', 'a', 'Acts 20:24 — "Neither count I my life dear unto myself, so that I might finish my course with joy, and the ministry." Paul''s motivation: course completion, not self-preservation. The athletic metaphor (dromos = race) appears in 2 Timothy 4:7 ("I have finished my course"). Freedom from the fear of death liberates for radical obedience.');

-- ═══ Acts Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 21, 'kids', 1, 'What did the prophet Agabus do with Paul''s belt to warn him?', 'He tied his own hands and feet with it and said the Jews in Jerusalem would bind Paul and deliver him to the Gentiles', 'He threw it into the river', 'He stretched it between two trees', 'He tied it around his own waist', 'a', 'Acts 21:11 — "And when he was come unto us, he took Paul''s girdle, and bound his own hands and feet, and said, Thus saith the Holy Ghost, So shall the Jews at Jerusalem bind the man that owneth this girdle, and shall deliver him into the hands of the Gentiles."'),
('Acts', 21, 'kids', 2, 'What did Paul say when his friends begged him not to go to Jerusalem?', 'I am ready not to be bound only, but also to die at Jerusalem for the name of the Lord Jesus', 'I am too afraid to go', 'Maybe I will change my plans', 'You are right, I should stay here', 'a', 'Acts 21:13 — "Then Paul answered, What mean ye to weep and to break mine heart? for I am ready not to be bound only, but also to die at Jerusalem for the name of the Lord Jesus."'),
('Acts', 21, 'kids', 3, 'What happened to Paul in the temple at Jerusalem?', 'Jews from Asia stirred up the crowd, grabbed him, and dragged him out of the temple, trying to kill him', 'He was welcomed with a big celebration', 'He taught a peaceful sermon', 'The priests gave him a gift', 'a', 'Acts 21:27,30 — "The Jews which were of Asia, when they saw him in the temple, stirred up all the people, and laid hands on him... and they took Paul, and drew him out of the temple."'),
-- Teens
('Acts', 21, 'teens', 1, 'What did the prophet Agabus predict would happen to Paul?', 'The Jews in Jerusalem would bind Paul and deliver him into the hands of the Gentiles — he acted it out by binding his own hands and feet with Paul''s belt', 'Paul would become the ruler of Jerusalem', 'A great earthquake would destroy the temple', 'Paul would be set free from all his enemies', 'a', 'Acts 21:11 — "He took Paul''s girdle, and bound his own hands and feet, and said, Thus saith the Holy Ghost, So shall the Jews at Jerusalem bind the man that owneth this girdle, and shall deliver him into the hands of the Gentiles."'),
('Acts', 21, 'teens', 2, 'What did James and the elders suggest Paul do to show he still respected the law?', 'Take four men who had a vow, go through the purification rites with them, and pay their expenses — to show everyone that Paul himself walked orderly and kept the law', 'Offer a sacrifice of one hundred lambs', 'Preach a sermon defending the law of Moses', 'Write a letter to all the synagogues', 'a', 'Acts 21:23-24 — "Take them, and purify thyself with them, and be at charges with them, that they may shave their heads: and all may know that those things, whereof they were informed concerning thee, are nothing; but that thou thyself also walkest orderly, and keepest the law."'),
('Acts', 21, 'teens', 3, 'Why did the Asian Jews start the riot against Paul in the temple?', 'They falsely accused Paul of bringing a Gentile (Trophimus the Ephesian) into the temple — they had seen Paul with him in the city and assumed he brought him into the temple', 'Paul had broken a temple lamp', 'Paul was wearing Gentile clothing', 'Paul had challenged the high priest publicly', 'a', 'Acts 21:28-29 — "This is the man, that teacheth all men every where against the people, and the law, and this place: and further brought Greeks also into the temple, and hath polluted this holy place. (For they had seen before with him in the city Trophimus an Ephesian, whom they supposed that Paul had brought into the temple.)"'),
('Acts', 21, 'teens', 4, 'Who rescued Paul from the mob that was trying to kill him?', 'The Roman chief captain and his soldiers, who ran down and arrested Paul, binding him with two chains', 'The temple priests stopped the crowd', 'Paul''s friends fought off the attackers', 'An angel appeared and frightened the mob', 'a', 'Acts 21:31-33 — "And as they went about to kill him, tidings came unto the chief captain of the band, that all Jerusalem was in an uproar. Who immediately took soldiers and centurions, and ran down unto them... and commanded him to be bound with two chains."'),
('Acts', 21, 'teens', 5, 'What did Paul ask the chief captain for permission to do?', 'To speak to the people from the stairs of the barracks — and he addressed the crowd in the Hebrew tongue', 'To be released from his chains', 'To send a letter to Rome', 'To return to the temple to pray', 'a', 'Acts 21:39-40 — "I beseech thee, suffer me to speak unto the people... he stood on the stairs, and beckoned with the hand unto the people. And when there was made a great silence, he spake unto them in the Hebrew tongue."'),
-- Adults
('Acts', 21, 'adults', 1, 'How does Agabus''s prophecy (21:10-14) relate to Paul''s determination to go to Jerusalem?', 'Agabus prophesies accurately (Paul will be bound and delivered to Gentiles) but does not command Paul to avoid Jerusalem. The friends'' plea ("we besought him not to go up") is their interpretation of the prophecy, not its content. Paul discerns that the Spirit reveals what will happen without forbidding it — knowing the cost does not change the calling. "The will of the Lord be done" (v.14) shows communal submission', 'Agabus forbade Paul to go to Jerusalem', 'Paul disobeyed the Holy Spirit by going', 'The prophecy was inaccurate', 'a', 'Acts 21:11-14 — Agabus says "Thus saith the Holy Ghost" but prophesies events, not commands. Compare 20:23 where the Spirit "witnesseth" bonds and afflictions without saying "don''t go." Paul distinguishes between prophetic revelation (this will happen) and divine command (do/don''t do this). The community submits: "The will of the Lord be done."'),
('Acts', 21, 'adults', 2, 'What does the James compromise (21:23-26) reveal about Paul''s flexibility and the Jerusalem church''s concerns?', 'Paul agrees to undergo a Nazirite purification to demonstrate that he does not oppose Jewish practice for Jewish believers — he opposes only imposing it on Gentiles. This is consistent with 1 Corinthians 9:20 ("unto the Jews I became as a Jew"). James''s concern is pastoral: thousands of Jewish believers are "zealous of the law" (v.20) and need reassurance. Paul accommodates for unity, not compromise', 'Paul was being hypocritical', 'James forced Paul to abandon his theology', 'Paul secretly opposed the law', 'a', 'Acts 21:20-24 — James reports "how many thousands of Jews there are which believe; and they are all zealous of the law." The purification rite was not a betrayal of Paul''s gospel but an application of his "all things to all men" principle (1 Corinthians 9:19-23). Jewish Christians could observe the law as long as it was not made a requirement for salvation.'),
('Acts', 21, 'adults', 3, 'How does the false charge against Paul (bringing Gentiles into the temple) echo a larger thematic issue in Acts?', 'The charge — that Paul "brought Greeks into the temple" (v.28) — is precisely what Paul''s gospel does spiritually: bringing Gentiles into God''s presence without the temple barrier. The physical accusation is false (Paul did not bring Trophimus in), but the spiritual reality is true: Christ broke down the "middle wall of partition" (Ephesians 2:14). The charge inadvertently captures the gospel''s revolutionary nature', 'The charge was completely irrelevant', 'Paul actually did bring Trophimus in', 'The barrier between Jew and Gentile was never discussed in Acts', 'a', 'Acts 21:28-29 — The temple''s Court of the Gentiles was separated by a wall with death-penalty inscriptions for Gentile trespassers (archaeological fragments survive). Paul''s gospel declares this wall abolished in Christ (Ephesians 2:14). The false physical charge ironically states the spiritual truth Paul proclaimed.'),
('Acts', 21, 'adults', 4, 'What does Paul''s arrest in the temple mark in the narrative structure of Acts?', 'Paul''s arrest begins his passion narrative — paralleling Jesus'' journey to Jerusalem, arrest, trials before Jewish and Roman authorities, and journey to Rome (=death). From chapter 21 to 28, Paul is a prisoner. Like Jesus, he enters Jerusalem knowing what awaits (cf. Luke 9:51, Acts 20:22-24), is seized in the temple, faces the Sanhedrin, is delivered to Roman custody, and is repeatedly declared innocent', 'The arrest is a minor incident', 'Paul''s story ends here', 'There are no parallels with Jesus'' passion', 'a', 'Acts 21:33 — Paul bound with two chains (cf. Jesus bound, Mark 15:1). The parallels with Jesus'' passion are extensive: Jerusalem journey with foreknowledge (20:22/Luke 9:51), temple arrest (21:30/Luke 22:54), Sanhedrin trial (22:30-23:10/Luke 22:66-71), Roman trial (24-26/Luke 23:1-25), innocence declared (23:29, 25:25, 26:31/Luke 23:4,14,22). Paul walks in his Master''s footsteps.'),
('Acts', 21, 'adults', 5, 'What does Luke''s mention of Philip the evangelist and his four prophesying daughters (21:8-9) contribute to the narrative?', 'Luke connects the current narrative to the earlier Jerusalem church (Philip from Acts 6-8), showing continuity. The four daughters who prophesy fulfil Joel 2:28-29 (quoted in Acts 2:17-18): "your sons and your daughters shall prophesy." Their mention validates women''s prophetic ministry and shows the Pentecostal promise being realised in the second generation of the church', 'Philip''s daughters are irrelevant detail', 'Only sons could prophesy', 'Philip was a different person from Acts 6', 'a', 'Acts 21:8-9 — "Philip the evangelist, which was one of the seven... the same man had four daughters, virgins, which did prophesy." Philip connects Acts 6 (the seven) with Acts 21. His prophesying daughters fulfil Acts 2:17-18 (Joel 2:28-29). Women prophesying demonstrates the Spirit''s gender-inclusive gifting.'),
('Acts', 21, 'adults', 6, 'How does the Roman military''s intervention (21:31-36) serve God''s purposes?', 'The Roman soldiers unwittingly save Paul''s life — the mob was "about to kill him" (v.31) when the chief captain intervened. Throughout Acts, Roman power inadvertently serves the gospel: protecting Paul from the mob, providing legal process, and eventually transporting him to Rome (fulfilling 23:11). God uses secular authority as an instrument of His sovereign plan', 'The Romans were trying to help Paul evangelise', 'Roman intervention was harmful to Paul', 'God only works through the church, not through secular powers', 'a', 'Acts 21:31-32 — "As they went about to kill him, tidings came unto the chief captain... Who immediately took soldiers and centurions, and ran down unto them." The Roman army saves the church''s greatest missionary. This pattern (secular power serving divine purposes) echoes Joseph in Egypt, Cyrus in Isaiah, and Pilate at the cross.'),
('Acts', 21, 'adults', 7, 'What does Paul''s request to address the crowd in Hebrew (21:39-40) reveal about his rhetorical strategy?', 'Paul identifies himself as a Tarsus citizen (credibility with the captain) and then speaks in Hebrew/Aramaic (connection with the Jewish crowd). By switching to the vernacular, he silences the mob ("when they heard that he spake in the Hebrew tongue, they kept the more silence," 22:2). Paul adapts his language to his audience — a consistent principle of his missionary method', 'Paul only spoke Hebrew', 'Speaking Hebrew was unusual for Paul', 'The crowd could not understand Hebrew', 'a', 'Acts 21:40, 22:2 — Paul''s strategic bilingualism: Greek to the Roman captain (21:37), Hebrew/Aramaic to the Jewish crowd (21:40). The crowd''s increased silence at hearing their own language demonstrates the power of cultural identification. Paul embodies his own principle: "I am made all things to all men" (1 Corinthians 9:22).'),
('Acts', 21, 'adults', 8, 'How does Acts 21 demonstrate the theme of divine sovereignty working through human opposition?', 'Every hostile act advances God''s plan: the riot leads to Roman custody, which leads to testimony before governors and kings (as Jesus predicted in Luke 21:12-13), which leads to Rome. The accusers intended to destroy Paul; God intended to transport him. The same pattern governs all of Acts: persecution scatters the church (8:1), opposition creates legal precedents (18:14-16), and imprisonment enables witness (28:30-31)', 'God was absent during Paul''s arrest', 'The arrest was a setback for the mission', 'Human opposition always defeats God''s purposes', 'a', 'Acts 21-28 — Paul''s arrest (21:33) leads to witness before the Sanhedrin (23:1), Felix (24:10), Festus (25:8), Agrippa (26:1), and ultimately Rome (28:16). Jesus had said: "Thou must bear witness also at Rome" (23:11). Every step of opposition becomes a step toward the mission''s completion.');

-- ═══════════════ CHAPTERS 22–24 ═══════════════

-- ═══ Acts Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 22, 'kids', 1, 'What did Paul tell the crowd about his life before he met Jesus?', 'He was brought up in Jerusalem, taught by Gamaliel according to the law, and was very zealous for God — he persecuted Christians', 'He was a fisherman from Galilee', 'He was a Roman soldier', 'He was a farmer in Egypt', 'a', 'Acts 22:3 — "I am verily a man which am a Jew, born in Tarsus, a city in Cilicia, yet brought up in this city at the feet of Gamaliel, and taught according to the perfect manner of the law of the fathers, and was zealous toward God."'),
('Acts', 22, 'kids', 2, 'What made the crowd stop listening and start shouting again?', 'When Paul said that Jesus had sent him to preach to the Gentiles', 'When Paul said something bad about Moses', 'When Paul refused to speak in Hebrew', 'When Paul asked them for money', 'a', 'Acts 22:21-22 — "And he said unto me, Depart: for I will send thee far hence unto the Gentiles. And they gave him audience unto this word, and then lifted up their voices, and said, Away with such a fellow from the earth: for it is not fit that he should live."'),
('Acts', 22, 'kids', 3, 'What stopped the Roman soldiers from whipping Paul?', 'Paul told them he was a Roman citizen, and it was against the law to beat a Roman without a trial', 'Paul ran away from the soldiers', 'An angel appeared and stopped them', 'The crowd demanded they let Paul go', 'a', 'Acts 22:25-26 — "And as they bound him with thongs, Paul said unto the centurion that stood by, Is it lawful for you to scourge a man that is a Roman, and uncondemned? When the centurion heard that, he went and told the chief captain."'),
-- Teens
('Acts', 22, 'teens', 1, 'How did Paul describe his encounter with Jesus on the road to Damascus?', 'A great light from heaven shone around him at noon, he fell to the ground, and heard a voice saying "Saul, Saul, why persecutest thou me?" — and the voice identified himself as Jesus of Nazareth', 'He saw a burning bush like Moses', 'An angel appeared with a written message', 'He heard a voice in the temple', 'a', 'Acts 22:6-8 — "And it came to pass, that, as I made my journey, and was come nigh unto Damascus about noon, suddenly there shone from heaven a great light round about me. And I fell unto the ground, and heard a voice saying unto me, Saul, Saul, why persecutest thou me? And I answered, Who art thou, Lord? And he said unto me, I am Jesus of Nazareth, whom thou persecutest."'),
('Acts', 22, 'teens', 2, 'What was the word that triggered the crowd''s violent reaction?', 'The word "Gentiles" — when Paul said the Lord sent him to preach to the Gentiles, the crowd erupted in rage', 'The word "Caesar"', 'The word "temple"', 'The word "Moses"', 'a', 'Acts 22:21-22 — "I will send thee far hence unto the Gentiles. And they gave him audience unto this word, and then lifted up their voices." The idea that God would include Gentiles on equal terms was intolerable to the crowd.'),
('Acts', 22, 'teens', 3, 'What did Ananias say to Paul about God''s purpose for him?', 'The God of our fathers hath chosen thee, that thou shouldest know his will, and see that Just One, and hear the voice of his mouth — and thou shalt be his witness unto all men', 'You should return to being a Pharisee', 'God wants you to stay in Damascus forever', 'You should become the high priest', 'a', 'Acts 22:14-15 — "The God of our fathers hath chosen thee, that thou shouldest know his will, and see that Just One, and shouldest hear the voice of his mouth. For thou shalt be his witness unto all men of what thou hast seen and heard."'),
('Acts', 22, 'teens', 4, 'How did the chief captain react when he learned Paul was a Roman citizen?', 'He was afraid because he had bound Paul without a trial, and he himself had bought his citizenship at a great price, while Paul was free-born', 'He did not care about Paul''s citizenship', 'He released Paul immediately', 'He called for Paul to be executed', 'a', 'Acts 22:28-29 — "And the chief captain answered, With a great sum obtained I this freedom. And Paul said, But I was free born. Then straightway they departed from him which should have examined him: and the chief captain also was afraid, after he knew that he was a Roman."'),
('Acts', 22, 'teens', 5, 'What did the chief captain do next to find out what Paul had done?', 'He commanded the chief priests and the Sanhedrin to assemble so he could bring Paul before them', 'He sent Paul to Rome immediately', 'He released Paul and closed the case', 'He asked the emperor for instructions', 'a', 'Acts 22:30 — "On the morrow, because he would have known the certainty wherefore he was accused of the Jews, he loosed him from his bands, and commanded the chief priests and all their council to appear, and brought Paul down, and set him before them."'),
-- Adults
('Acts', 22, 'adults', 1, 'How does Paul''s second telling of his conversion (Acts 22) adapt the story for a Jewish audience?', 'Paul emphasises his impeccable Jewish credentials: born in Tarsus but raised in Jerusalem, trained under Gamaliel, zealous for the law (v.3). He highlights Ananias as "a devout man according to the law, having a good report of all the Jews" (v.12) and frames his commission in terms of the God of their fathers (v.14). He delays the explosive word "Gentiles" until the end — showing rhetorical sensitivity to his audience', 'Paul told the same story identically every time', 'He omitted his Jewish background', 'He emphasised his Gentile connections', 'a', 'Acts 22:3,12,14 — Paul tailors his testimony: Jewish pedigree (Gamaliel), Ananias''s Jewish credentials, the "God of our fathers" formula. He builds maximum common ground before the divisive climax: "I will send thee far hence unto the Gentiles" (v.21). Contextualisation is not compromise — it is wisdom.'),
('Acts', 22, 'adults', 2, 'Why did the mention of "Gentiles" provoke such violent rage from the crowd?', 'The crowd tolerated Paul''s testimony about a heavenly vision and even a commission to witness — but the claim that Israel''s God would send a Jewish apostle specifically to Gentiles crossed an ideological boundary. This implied Gentile equality before God, which threatened Jewish ethnic privilege and national identity. The rage reveals that exclusivism, not theology, was the real issue', 'The crowd was angry about a different word', 'They objected to Paul''s vision, not his mission', 'Gentile inclusion was universally accepted', 'a', 'Acts 22:21-22 — "Gentiles" triggered the explosion. The crowd could tolerate Paul''s Damascus road story but not its implication: God''s salvation for Gentiles on equal terms. This mirrors Nazareth''s rage when Jesus cited God''s blessings on Gentiles (Luke 4:24-29). Jewish exclusivism could not tolerate a universal gospel.'),
('Acts', 22, 'adults', 3, 'What does Paul''s Roman citizenship reveal about his social position and how he uses it strategically?', 'Paul was born a Roman citizen (civis Romanus natus) — a privilege his family acquired, suggesting either notable service or wealth. He uses it strategically: not to avoid suffering (he had already been beaten) but to prevent extrajudicial punishment that could discredit the gospel. At Philippi (16:37), he used it to protect the church; here he uses it to ensure proper legal process', 'Paul invented his citizenship claim', 'Roman citizenship was common and unimportant', 'Paul always used citizenship to avoid suffering', 'a', 'Acts 22:25-28 — The centurion "bought" his citizenship (v.28), but Paul was "free born" — born into it, suggesting a family of some status. Paul deploys citizenship selectively: he suffered without invoking it many times (2 Corinthians 11:25). Here, scourging would have been extrajudicial torture (examination by flogging) — Paul prevents this abuse of Roman law.'),
('Acts', 22, 'adults', 4, 'What does Paul''s temple vision (22:17-21) add to the conversion accounts that chapters 9 and 26 omit?', 'This account uniquely includes a post-conversion temple vision where Jesus directly tells Paul to leave Jerusalem because they "will not receive thy testimony" and specifically commissions him: "I will send thee far hence unto the Gentiles." This vision, only recorded here, connects Paul''s Gentile mission directly to a dominical command received in the temple itself — God sent Paul from the holiest Jewish space to the Gentile world', 'The temple vision appears in all three accounts', 'It contradicts the other conversion narratives', 'Paul invented the vision for rhetorical purposes', 'a', 'Acts 22:17-21 — This temple trance is unique to the Acts 22 account. It accomplishes two things for the Jewish audience: (1) Paul was praying in the temple (not opposing it), and (2) his Gentile mission was a direct divine command, not personal choice. The irony: the temple itself sent Paul to the Gentiles.'),
('Acts', 22, 'adults', 5, 'How does the chief captain''s purchased versus Paul''s inherited citizenship illustrate Roman social dynamics?', 'Claudius Lysias "bought" (ektesamen) citizenship at "great price" — common under Emperor Claudius when freedmen sold citizenship for profit. Paul''s freeborn status (eleutheros) was higher, acquired through family (possibly ancestors received it for service to Rome). The contrast reveals social stratification: purchased citizens were common but freeborn citizens had greater prestige. Paul''s status gives him legal superiority over his own captor', 'Both types of citizenship were identical', 'Purchased citizenship was more prestigious', 'Paul''s citizenship was unverifiable', 'a', 'Acts 22:28 — "With a great sum obtained I this freedom. But I was free born." Under Claudius, citizenship sales were widespread (Dio Cassius 60.17). Birth citizenship (from a citizen father) was more prestigious. The irony: the Roman commander is socially outranked by his prisoner — Roman law protects Paul against Roman abuse.'),
('Acts', 22, 'adults', 6, 'What does Paul''s appeal to his persecuting past (22:4-5,19-20) serve in his rhetorical argument?', 'By emphasising his former zeal against Christians — "I persecuted this way unto the death" (v.4), "I imprisoned and beat them" (v.19), "I kept the raiment of them that slew Stephen" (v.20) — Paul establishes two things: he understands his audience''s hostility (he once shared it), and only divine intervention could have changed him. The dramatic reversal makes his testimony compelling — he was the least likely convert', 'Paul was boasting about his past', 'His persecution history was irrelevant', 'Paul was trying to gain sympathy from the Romans', 'a', 'Acts 22:4-5,19-20 — Paul''s pre-conversion biography mirrors his audience''s current hostility: "I persecuted this way unto the death." His point: I was exactly like you — zealous, violent, convinced I was right. Only a divine intervention of overwhelming power could have turned the church''s greatest enemy into its greatest advocate.'),
('Acts', 22, 'adults', 7, 'How does Luke use the chief captain''s investigation to advance his apologetic purposes?', 'Claudius Lysias represents Roman justice seeking the truth. His process — rescuing Paul, investigating the charges, arranging a hearing before the Sanhedrin — shows Roman administration functioning properly. Luke consistently portrays Roman officials as procedurally fair (Gallio, Lysias, Felix, Festus, Agrippa), reinforcing the argument that Christianity is not a criminal movement', 'Luke was criticising Roman administration', 'The chief captain had no interest in justice', 'Roman procedure was irrelevant to Luke''s purposes', 'a', 'Acts 22:24,30 — Lysias investigates fairly: he rescues Paul (21:32), attempts examination (22:24), stops when he learns of citizenship (22:29), and convenes the Sanhedrin for a proper hearing (22:30). Luke''s apologetic: Roman officials who investigate fairly find Christianity innocent. The system works; only Jewish hostility creates the problem.'),
('Acts', 22, 'adults', 8, 'What does Ananias''s description as "a devout man according to the law, having a good report of all the Jews" (22:12) accomplish rhetorically?', 'By presenting Ananias as an observant Jew respected by the Jewish community — not a law-breaking renegade — Paul undermines the narrative that Christians are enemies of Judaism. Ananias represents the many Jewish believers who faithfully observe the law. Paul''s messenger was an impeccably Jewish disciple, showing that the gospel is not anti-Jewish but the fulfilment of Jewish faith', 'Ananias was actually a Gentile', 'His Jewish credentials were unimportant', 'Paul was exaggerating about Ananias', 'a', 'Acts 22:12 — "And one Ananias, a devout man according to the law, having a good report of all the Jews which dwelt there." In Acts 9, Ananias is simply "a disciple." Here Paul highlights his Jewish piety for his Jewish audience — showing that faithful Jews can embrace Jesus without abandoning the law. The gospel is not apostasy from Judaism.');

-- ═══ Acts Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 23, 'kids', 1, 'What did Paul cleverly say to divide the Sanhedrin?', 'I am a Pharisee and I am being judged for believing in the resurrection of the dead — this caused the Pharisees and Sadducees to argue with each other', 'He told them a riddle they could not answer', 'He challenged them to a contest', 'He asked them to vote on his case', 'a', 'Acts 23:6-7 — "But when Paul perceived that the one part were Sadducees, and the other Pharisees, he cried out in the council, Men and brethren, I am a Pharisee, the son of a Pharisee: of the hope and resurrection of the dead I am called in question. And when he had so said, there arose a dissension between the Pharisees and the Sadducees."'),
('Acts', 23, 'kids', 2, 'What encouraging message did the Lord give Paul at night?', 'Be of good cheer, Paul: for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome', 'Go back to Tarsus and rest', 'Build a church in this city', 'Everything will be easy from now on', 'a', 'Acts 23:11 — "And the night following the Lord stood by him, and said, Be of good cheer, Paul: for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome."'),
('Acts', 23, 'kids', 3, 'Who warned the Roman soldiers about a secret plot to kill Paul?', 'Paul''s nephew — his sister''s son heard about the plot and told the chief captain', 'An angel appeared to the captain', 'A Pharisee wrote a secret letter', 'Paul had a dream about it', 'a', 'Acts 23:16 — "And when Paul''s sister''s son heard of their lying in wait, he went and entered into the castle, and told Paul."'),
-- Teens
('Acts', 23, 'teens', 1, 'What was the difference between the Pharisees and Sadducees that Paul used to his advantage?', 'The Sadducees say there is no resurrection, nor angel, nor spirit, but the Pharisees confess all three — Paul declared himself a Pharisee judged for believing in the resurrection, splitting the council', 'The Sadducees wore white and the Pharisees wore black', 'The Pharisees were richer than the Sadducees', 'The Sadducees were from Galilee and the Pharisees from Judaea', 'a', 'Acts 23:8 — "For the Sadducees say that there is no resurrection, neither angel, nor spirit: but the Pharisees confess both."'),
('Acts', 23, 'teens', 2, 'How many men made an oath not to eat or drink until they had killed Paul?', 'More than forty men', 'Twelve men', 'Seven men', 'One hundred men', 'a', 'Acts 23:13 — "And they were more than forty which had made this conspiracy."'),
('Acts', 23, 'teens', 3, 'What did the chief captain do after learning of the plot to kill Paul?', 'He sent Paul to Governor Felix in Caesarea with a guard of two hundred soldiers, seventy horsemen, and two hundred spearmen — by night', 'He moved Paul to a different prison cell', 'He dismissed the Jewish leaders', 'He ignored the threat as insignificant', 'a', 'Acts 23:23-24 — "He called unto him two centurions, saying, Make ready two hundred soldiers to go to Caesarea, and horsemen threescore and ten, and spearmen two hundred, at the third hour of the night; And provide them beasts, that they may set Paul on, and bring him safe unto Felix the governor."'),
('Acts', 23, 'teens', 4, 'What did the chief captain write in his letter to Governor Felix about Paul?', 'That Paul was accused by the Jews concerning questions of their law but had committed no crime worthy of death or imprisonment', 'That Paul was a dangerous criminal who should be executed', 'That Paul was a Roman spy', 'That Paul should be sent back to Jerusalem', 'a', 'Acts 23:29 — "Whom I perceived to be accused of questions of their law, but to have nothing laid to his charge worthy of death or of bonds."'),
('Acts', 23, 'teens', 5, 'What happened when the high priest Ananias commanded someone to strike Paul on the mouth?', 'Paul said "God shall smite thee, thou whited wall" — and when told he had spoken against the high priest, Paul said he did not know it was the high priest', 'Paul turned the other cheek silently', 'Paul struck back immediately', 'Paul asked the guards to protect him', 'a', 'Acts 23:2-5 — "The high priest Ananias commanded them that stood by him to smite him on the mouth. Then said Paul unto him, God shall smite thee, thou whited wall... Then said Paul, I wist not, brethren, that he was the high priest: for it is written, Thou shalt not speak evil of the ruler of thy people."'),
-- Adults
('Acts', 23, 'adults', 1, 'What does the Lord''s night vision to Paul (23:11) accomplish narratively and theologically?', 'The vision confirms three things: encouragement ("be of good cheer"), validation of Paul''s Jerusalem testimony, and the divine promise of Rome ("so must thou bear witness also at Rome"). The word "must" (dei) makes the Roman mission a divine necessity. From this point, every obstacle (assassination plot, imprisonment, shipwreck) is reframed: nothing can prevent what God has decreed', 'The vision was Paul''s imagination', 'It only affected Paul personally', 'The vision was conditional on Paul''s obedience', 'a', 'Acts 23:11 — "Be of good cheer, Paul: for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome." The divine "must" (dei) makes Paul''s arrival in Rome as certain as prophecy. Every subsequent chapter confirms this: the assassination plot fails, Felix keeps Paul but cannot harm him, Festus sends him to Caesar, the shipwreck does not kill him.'),
('Acts', 23, 'adults', 2, 'Was Paul''s exploitation of the Pharisee-Sadducee division (23:6-8) legitimate strategy or dishonest manipulation?', 'Paul''s claim to be "a Pharisee, the son of a Pharisee" was factually true, and his statement about resurrection was the genuine theological issue. The resurrection was both the doctrinal point of contention and the heart of the gospel. Paul framed the trial correctly: the real issue was whether Jesus rose from the dead. His strategy was truthful even if tactically shrewd', 'Paul was lying about being a Pharisee', 'The resurrection was irrelevant to the case', 'Paul was simply being manipulative', 'a', 'Acts 23:6 — Paul''s double claim is factual: he was a Pharisee by training (Philippians 3:5) and the resurrection was indeed the core issue (cf. 24:15,21; 26:6-8). By identifying the theological centre, Paul exposed the council''s internal contradictions and prevented a unified condemnation. Truth and strategy aligned.'),
('Acts', 23, 'adults', 3, 'What does Paul''s response to the high priest ("God shall smite thee, thou whited wall") echo, and how does Paul handle the aftermath?', 'Paul''s "whited wall" echoes Jesus'' "whited sepulchres" (Matthew 23:27) — both describe hypocrisy that appears righteous outside but is corrupt within. When informed he addressed the high priest, Paul immediately quotes Exodus 22:28 ("Thou shalt not speak evil of the ruler of thy people"), showing respect for the office despite condemning the man''s injustice. His retraction shows submission to Scripture', 'Paul was simply rude with no deeper meaning', 'He deliberately insulted the high priest', 'Paul never corrected himself', 'a', 'Acts 23:3,5 — "Whited wall" parallels Matthew 23:27. Paul''s correction ("I wist not that he was the high priest") may be literal (poor eyesight, unfamiliar robes) or ironic (this man acts nothing like a high priest). Either way, Paul defers to Scripture (Exodus 22:28), modelling principle over emotion.'),
('Acts', 23, 'adults', 4, 'How does the assassination conspiracy (23:12-22) and its failure illustrate divine providence?', 'Forty men take an oath to kill Paul, devising an elaborate ambush plan. Yet God thwarts the conspiracy through an ordinary means — Paul''s nephew overhearing the plot. The providential chain: a boy hears, tells Paul, Paul sends him to the captain, and an army of 470 soldiers escorts Paul to safety. God''s sovereignty operates through human intelligence-gathering and military logistics', 'The conspiracy was never a real threat', 'Paul escaped through his own cleverness', 'God used supernatural means to save Paul', 'a', 'Acts 23:12-24 — The plot: 40+ men, an oath, a trap. The counter: one nephew, one message, one captain, 470 soldiers. God''s protection works through ordinary means: family connections, military protocols, and administrative transfers. No miracle occurs — yet the outcome is as certain as if an angel appeared, because God promised Rome (v.11).'),
('Acts', 23, 'adults', 5, 'What does Claudius Lysias''s letter to Felix (23:25-30) reveal about how Roman officials reported on Paul?', 'The letter sanitises Lysias''s own conduct (he omits binding Paul illegally and ordering the flogging) while accurately reporting that Paul committed no crime worthy of death. Despite the self-serving editing, the letter''s essential conclusion serves Luke''s apologetic: a Roman official finds no criminal charge against Paul. Luke includes the letter to show that secular authorities exonerated Christianity', 'The letter was completely accurate', 'Lysias condemned Paul in the letter', 'The letter was invented by Luke', 'a', 'Acts 23:27-29 — Lysias claims he rescued Paul because "I understood that he was a Roman" — actually, he learned this only after arresting and nearly flogging him. The self-serving revision aside, the critical verdict stands: "nothing laid to his charge worthy of death or of bonds" (v.29). Luke''s interest is the exoneration.'),
('Acts', 23, 'adults', 6, 'How does Paul''s transfer from Jerusalem to Caesarea advance both the plot and the theological theme of Acts?', 'The transfer removes Paul from the volatile Jerusalem environment to the Roman administrative capital of Judaea, placing him under direct Roman jurisdiction. This sets up the extended trial narratives (chapters 24-26) before Felix, Festus, and Agrippa, fulfilling both 23:11 (Rome) and Jesus'' prediction that disciples would testify before governors and kings (Luke 21:12-13)', 'The transfer was a routine administrative matter', 'Paul preferred Caesarea to Jerusalem', 'The transfer delayed the gospel', 'a', 'Acts 23:23-33 — Jerusalem to Caesarea: from Jewish jurisdiction to Roman. This geographic shift mirrors Acts'' overall movement from Jewish centre to Roman capital. Paul will testify before Felix (governor), Festus (governor), and Agrippa (king) — fulfilling Luke 21:12-13 and Acts 9:15 ("to bear my name before Gentiles, and kings").'),
('Acts', 23, 'adults', 7, 'What does the Pharisees'' defence of Paul (23:9 — "if a spirit or an angel hath spoken to him, let us not fight against God") recall from earlier in Acts?', 'This echoes Gamaliel''s counsel in Acts 5:38-39 ("if it be of God, ye cannot overthrow it; lest haply ye be found even to fight against God"). The Pharisees use the same theological logic: if Paul''s experience is divine, opposing him means fighting God. Luke shows that even Paul''s enemies sometimes speak truth, and the Pharisaic caution about opposing God proves wiser than the Sadducean rejection', 'The Pharisees had never defended a Christian before', 'This has no connection to Gamaliel''s speech', 'The Pharisees were all secret Christians', 'a', 'Acts 23:9 — "If a spirit or an angel hath spoken to him, let us not fight against God." This directly echoes Gamaliel (5:39). The Pharisees'' openness to resurrection, angels, and spirits (v.8) makes them natural, if temporary, allies. Luke shows the Pharisees unwittingly vindicating the gospel.'),
('Acts', 23, 'adults', 8, 'What does the massive military escort (470 soldiers) reveal about the perceived threat level and Roman administrative priorities?', 'The escort — 200 soldiers, 70 horsemen, 200 spearmen — for one prisoner is extraordinary, revealing both the serious threat of the assassination conspiracy and the Roman military''s investment in protecting a citizen. The nighttime departure (third hour of the night = 9pm) adds further secrecy. Luke may also intend irony: God''s chosen apostle travels to his destiny with an imperial army as unwitting escort', 'The escort size was normal for any prisoner', 'Luke exaggerated the numbers', 'Paul requested the large escort', 'a', 'Acts 23:23 — 470 soldiers for one man: nearly half a cohort. The scale reflects both the danger (40+ assassins) and Roman seriousness about protecting citizens. The theological irony: Rome''s military machine, designed to maintain pagan order, serves as God''s instrument to deliver His apostle toward his destined testimony.');

-- ═══ Acts Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Acts', 24, 'kids', 1, 'Who came to accuse Paul before Governor Felix?', 'The high priest Ananias, some elders, and a lawyer named Tertullus', 'The Roman emperor', 'King Herod', 'The twelve apostles', 'a', 'Acts 24:1 — "And after five days Ananias the high priest descended with the elders, and with a certain orator named Tertullus, who informed the governor against Paul."'),
('Acts', 24, 'kids', 2, 'What did Paul say he believed?', 'Everything written in the law and the prophets, and he had hope toward God that there shall be a resurrection of the dead', 'Only in the law of Moses', 'Only in what the Pharisees taught', 'Nothing that the prophets wrote', 'a', 'Acts 24:14-15 — "So worship I the God of my fathers, believing all things which are written in the law and in the prophets: And have hope toward God... that there shall be a resurrection of the dead, both of the just and unjust."'),
('Acts', 24, 'kids', 3, 'Why did Governor Felix keep Paul in prison for two years?', 'He hoped Paul would give him money, and he also wanted to do the Jews a favour', 'Paul asked to stay in prison', 'Felix forgot about Paul', 'The trial was very complicated', 'a', 'Acts 24:26-27 — "He hoped also that money should have been given him of Paul, that he might loose him... But after two years Porcius Festus came into Felix'' room: and Felix, willing to shew the Jews a pleasure, left Paul bound."'),
-- Teens
('Acts', 24, 'teens', 1, 'What were the charges that Tertullus brought against Paul?', 'He called Paul a pestilent fellow, a mover of sedition among the Jews throughout the world, a ringleader of the sect of the Nazarenes, and one who had profaned the temple', 'Paul had refused to pay Roman taxes', 'Paul had stolen money from the temple treasury', 'Paul had plotted to overthrow the governor', 'a', 'Acts 24:5-6 — "For we have found this man a pestilent fellow, and a mover of sedition among all the Jews throughout the world, and a ringleader of the sect of the Nazarenes: Who also hath gone about to profane the temple."'),
('Acts', 24, 'teens', 2, 'How did Paul defend himself against the charges?', 'He denied causing any disturbance — no one found him disputing or stirring up the people. He confessed believing in the Way, worshipping the God of his fathers, and believing all things in the law and prophets', 'He pleaded guilty to all charges', 'He refused to speak in his own defence', 'He accused Tertullus of lying about everything', 'a', 'Acts 24:12-14 — "They neither found me in the temple disputing with any man, neither raising up the people, neither in the synagogues, nor in the city... But this I confess unto thee, that after the way which they call heresy, so worship I the God of my fathers."'),
('Acts', 24, 'teens', 3, 'What topics did Paul discuss with Felix in private?', 'Righteousness, temperance, and judgment to come — and Felix trembled', 'Military strategy and politics', 'Roman law and citizenship', 'Trade routes and commerce', 'a', 'Acts 24:25 — "And as he reasoned of righteousness, temperance, and judgment to come, Felix trembled, and answered, Go thy way for this time; when I have a convenient season, I will call for thee."'),
('Acts', 24, 'teens', 4, 'What was Felix hoping to get from Paul?', 'Money — he hoped Paul or his friends would offer him a bribe for Paul''s release', 'A recommendation to the emperor', 'A cure for a disease', 'Permission to visit the church in Antioch', 'a', 'Acts 24:26 — "He hoped also that money should have been given him of Paul, that he might loose him: wherefore he sent for him the oftener, and communed with him."'),
('Acts', 24, 'teens', 5, 'How long was Paul kept in custody in Caesarea under Felix?', 'Two years, until Felix was replaced by Porcius Festus', 'Six months', 'One month', 'Five years', 'a', 'Acts 24:27 — "But after two years Porcius Festus came into Felix'' room: and Felix, willing to shew the Jews a pleasure, left Paul bound."'),
-- Adults
('Acts', 24, 'adults', 1, 'How does Tertullus''s speech (24:2-8) employ standard Roman forensic rhetoric?', 'Tertullus opens with a captatio benevolentiae (flattery of Felix, vv.2-4), then presents three charges: sedition (political — "a mover of sedition"), sectarianism (social — "ringleader of the sect of the Nazarenes"), and sacrilege (religious — "profaned the temple"). The charges are strategically crafted to concern Rome (sedition), Jewish leadership (sectarianism), and the temple authorities (sacrilege)', 'Tertullus was untrained in rhetoric', 'He presented only one charge', 'His speech had no rhetorical structure', 'a', 'Acts 24:2-6 — Tertullus''s speech follows classical Roman forensic form: exordium (flattery, vv.2-4), narratio (charges, vv.5-6), and peroratio (appeal, vv.8). The three charges cover political (sedition), social (sect leadership), and religious (temple profanation) dimensions — designed to appeal to Felix on every front.'),
('Acts', 24, 'adults', 2, 'How does Paul''s defence redefine "the Way" as legitimate Judaism rather than heresy?', 'Paul insists that "the Way" is not a heretical sect but the true expression of ancestral faith: "I worship the God of my fathers, believing all things which are written in the law and in the prophets" (v.14). He claims continuity with Judaism, not departure from it. The "heresy" charge (hairesis = sect) is reframed: Christianity is Judaism fulfilled, not Judaism abandoned', 'Paul admitted the Way was a new religion', 'He agreed it was a heretical sect', 'Paul made no connection to Judaism', 'a', 'Acts 24:14-15 — Paul''s defence: the Way worships Israel''s God, believes Israel''s Scriptures, and hopes for Israel''s resurrection. He adds: "they themselves also allow, that there shall be a resurrection of the dead" (v.15) — Pharisees believe the same thing. Paul positions Christianity as within Judaism, not outside it.'),
('Acts', 24, 'adults', 3, 'What does Felix''s response — trembling at Paul''s preaching on "righteousness, temperance, and judgment to come" (24:25) — reveal about the gospel''s power and the human will?', 'Felix trembled (emphobos genomenos = became terrified) because Paul''s message convicted him personally — Felix was notorious for corruption and had stolen his wife Drusilla from her husband. Yet conviction did not produce conversion: "when I have a convenient season" became permanent postponement. Felix illustrates how a person can be deeply moved by truth yet refuse to submit, choosing deferral over decision', 'Felix was physically cold', 'Paul''s preaching was ineffective', 'Felix was already a believer', 'a', 'Acts 24:25 — "Felix trembled, and answered, Go thy way for this time; when I have a convenient season, I will call for thee." Josephus records Felix''s corruption and violence (Antiquities 20.7-8). Paul''s topics (righteousness, self-control, judgment) targeted Felix''s known sins. The "convenient season" never came — Felix exemplifies the tragedy of deferred repentance.'),
('Acts', 24, 'adults', 4, 'What does Felix''s two-year detention of Paul reveal about Roman justice and political expediency?', 'Felix delayed judgment not because the case was complex but because he wanted a bribe (v.26) and wanted to please the Jews (v.27). Roman justice was corrupted by personal greed and political calculation. Yet even this injustice served God''s purposes: the two-year delay protected Paul from Jewish assassination plots and positioned him for transfer to a new governor who would send him to Rome', 'Felix detained Paul for legitimate legal reasons', 'Two years was a standard waiting period', 'Paul was content to remain in prison', 'a', 'Acts 24:26-27 — Dual corruption: bribery (hoping for money) and political calculation (willing to show the Jews a pleasure). Felix violated Roman legal norms by refusing to decide. Yet God''s sovereignty operates even through unjust systems: the delay kept Paul safe and alive for Rome.'),
('Acts', 24, 'adults', 5, 'How does Paul''s claim of "a conscience void of offence toward God, and toward men" (24:16) function in his defence?', 'Paul claims moral integrity as evidence against the charges — a clear conscience before both God (religious dimension) and men (social dimension). This is not a claim to sinless perfection but to consistent effort to live rightly. In forensic terms, Paul offers his character as evidence: a man of good conscience does not provoke riots or profane temples', 'Paul was claiming sinless perfection', 'This was irrelevant to the legal case', 'Paul was being dishonest', 'a', 'Acts 24:16 — "And herein do I exercise myself, to have always a conscience void of offence toward God, and toward men." The word "exercise" (askein) means disciplined training — Paul works at maintaining integrity. In Roman courts, character witnesses mattered. Paul presents his consistent moral effort as evidence refuting the charges.'),
('Acts', 24, 'adults', 6, 'What does Paul''s mention of "alms and offerings" (24:17) contribute to his defence?', 'Paul reveals his purpose for coming to Jerusalem was charitable and liturgical — "to bring alms to my nation, and offerings." He was bringing the collection from Gentile churches (cf. Romans 15:25-28, 1 Corinthians 16:1-4). A man bringing charitable gifts is an unlikely temple profaner. This detail rebuts the charge of hostile intent and reveals his goodwill toward his own people', 'Paul was trying to bribe the court', 'The alms were for himself', 'This detail was irrelevant', 'a', 'Acts 24:17 — "Now after many years I came to bring alms to my nation, and offerings." This is the only Acts reference to Paul''s great collection (cf. Romans 15:25-28, 2 Corinthians 8-9, Galatians 2:10). Paul''s purpose was benevolent, not hostile — evidence of love for his own nation, not contempt for its institutions.'),
('Acts', 24, 'adults', 7, 'How does Felix having "more perfect knowledge of that way" (24:22) affect his legal and moral responsibility?', 'Felix already knew about Christianity ("having more perfect knowledge of that way") — possibly through his Jewish wife Drusilla (v.24). His knowledge made his deferral more culpable: he was not ignorant but informed, not confused but corrupt. Like Herod with John the Baptist (Mark 6:20 — "heard him gladly"), Felix was fascinated by truth but refused to submit to it', 'Felix was completely ignorant of Christianity', 'His knowledge excused his decisions', 'Felix was neutral and fair', 'a', 'Acts 24:22,24 — Felix had prior knowledge of "the Way" and sent for Paul frequently to discuss "the faith in Christ" with Drusilla. His knowledge increased his guilt: he delayed not from confusion but from corruption. Jesus taught that greater knowledge brings greater accountability (Luke 12:47-48).'),
('Acts', 24, 'adults', 8, 'How do chapters 22-24 collectively demonstrate that Paul committed no crime against Roman or Jewish law?', 'Through three hearings — the crowd (ch.22), the Sanhedrin (ch.23), and Felix (ch.24) — no formal charge sticks. Lysias found no Roman crime (23:29), the Sanhedrin could not agree (23:10), and Felix deferred without conviction (24:22-27). Luke systematically shows Paul declared innocent at every level, building a cumulative legal apologetic: Christianity threatens neither Rome nor Judaism', 'Paul was found guilty at one hearing', 'Only one hearing took place', 'The legal proceedings were irrelevant to Luke', 'a', 'Acts 22-24 — Lysias: "nothing worthy of death or of bonds" (23:29). The Sanhedrin: split with Pharisees defending Paul (23:9). Felix: no verdict, only delay (24:22-27). Luke''s legal apologetic accumulates: three proceedings, zero convictions. Christianity is legally vindicated at every turn.');
